// VanJS Lucide - Logs
import van from "vanjs-core";
import { LucideIcon, svgNamespace } from "../LucideIcon.ts";
import { type SVGProps } from "../types.ts";

export const Logs = (props: Partial<SVGProps> = {}) => {
  const { path } = van.tags(svgNamespace);

  return LucideIcon(
    props,
    path({ "d": "M3 5h1" }),
    path({ "d": "M3 12h1" }),
    path({ "d": "M3 19h1" }),
    path({ "d": "M8 5h1" }),
    path({ "d": "M8 12h1" }),
    path({ "d": "M8 19h1" }),
    path({ "d": "M13 5h8" }),
    path({ "d": "M13 12h8" }),
    path({ "d": "M13 19h8" }),
  );
};
