// VanJS Lucide - CircleEllipsis
import van from "vanjs-core";
import { LucideIcon, svgNamespace } from "../LucideIcon.ts";
import { type SVGProps } from "../types.ts";

export const CircleEllipsis = (props: Partial<SVGProps> = {}) => {
  const { circle, path } = van.tags(svgNamespace);

  return LucideIcon(
    props,
    circle({
      cx: "12",
      cy: "12",
      "r": "10",
    }),
    path({ "d": "M17 12h.01" }),
    path({ "d": "M12 12h.01" }),
    path({ "d": "M7 12h.01" }),
  );
};
